import{_ as r,o as a,c as p,a7 as o}from"./chunks/framework.BgApuQ2e.js";const n="/images/marriage-decision/R1-girlfriend.png",i="/images/marriage-decision/R2-on-a-cloud.jpg",s="/images/marriage-decision/R3-smiling-1.png",g="/images/marriage-decision/R4-love-you.png",m="/images/marriage-decision/R5-Unicorns.jpg",c="/images/marriage-decision/R6-angry.png",l="/images/marriage-decision/R7-Cage.png",h="/images/marriage-decision/R8-ball-and-chain.png",u="/images/marriage-decision/R9-best.png",d="/images/marriage-decision/R10-worst.png",_="/images/marriage-decision/R11-teammate.png",w="/images/marriage-decision/R12-rock.png",b="/images/marriage-decision/R13-beam-1.jpg",f="/images/marriage-decision/R14-beam-2.jpg",y="/images/marriage-decision/R15-beam-3.jpg",k="/images/marriage-decision/R16-beam-4.jpg",q="/images/marriage-decision/fear-breakup-2.png",R="/images/marriage-decision/fear-marriage-2.png",v="/images/marriage-decision/gut.png",T="/images/marriage-decision/house.jpg",P="/images/marriage-decision/road.jpg",t="/images/marriage-decision/Venn.png",j="/images/marriage-decision/R17-beam-5-1.png",I="/images/marriage-decision/pinit_fg_en_rect_gray_20.png",V=JSON.parse('{"title":"The Marriage Decision: Everything Forever or Nothing Ever Again","description":"","frontmatter":{"title":"The Marriage Decision: Everything Forever or Nothing Ever Again","titleZh":"婚姻抉择:永远相守或永不再见","date":"2016-09-01T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2016/09/marriage-decision.html","slug":"marriage-decision"},"headers":[],"relativePath":"posts/marriage-decision.md","filePath":"posts/marriage-decision.md","lastUpdated":1782886257000}'),D={name:"posts/marriage-decision.md"};function A(E,e,W,H,N,B){return a(),p("div",null,[...e[0]||(e[0]=[o('<h1 id="婚姻抉择-永远相守或永不再见-·-the-marriage-decision-everything-forever-or-nothing-ever-again" tabindex="-1">婚姻抉择:永远相守或永不再见 · The Marriage Decision: Everything Forever or Nothing Ever Again <a class="header-anchor" href="#婚姻抉择-永远相守或永不再见-·-the-marriage-decision-everything-forever-or-nothing-ever-again" aria-label="Permalink to &quot;婚姻抉择:永远相守或永不再见 · The Marriage Decision: Everything Forever or Nothing Ever Again&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2016/09/marriage-decision.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2016/09/marriage-decision.html</a> · 2016-09-01</p></blockquote><p>一段恋爱关系的开始其实没什么标准套路。有些人先约会一次,再约会一次,再来一次,某一天两个人心里都清楚:我们在谈恋爱了。有些人开始处对象,但一直不明不白,直到某次&quot;那咱俩这算什么啊?&quot;的对话,才把事情敲定。有时候两个人先是柏拉图式的朋友,水面下的暗流慢慢积累,直到某个出乎意料的吻,把这段友谊点着了。</p><p>但通常都会有那么一个&quot;第一次&quot;:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R1-girlfriend.png" target="_blank" rel="noreferrer"><img src="'+n+'" alt="(holding hands) stick 1: so does this mean... that you&#39;re my girlfriend? / stick 2: yeah... I think that&#39;s what it means..."></a></p><p>然后突然之间,你就到了这里:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R2-on-a-cloud.jpg" target="_blank" rel="noreferrer"><img src="'+i+'" alt="couple floating on a cloud"></a></p><p>这段崭新的恋情随时都陪着你,哪怕你俩没在一起。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/R3-smiling-1.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="smiling on a subway car"></a></p><p>你把剩下那一堆糟心人类都甩在了身后,感觉爽极了。然后就发生了这个:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/R4-love-you.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="stick figure couple on park bench. &quot;I love you&quot;"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R5-Unicorns.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt="stick figure couple riding unicorns"></a></p><p>所有情歌的歌词你都秒懂了。</p><p>这样的日子持续一阵子,但几个月过去,你会注意到有些东西开始变了。独角兽变成了马,又变成了自行车,然后某一天,你发现你脚下什么坐骑都没有。你当初找到的那个完美的人,开始说一些、做一些不那么完美的事。那些早期你觉得可爱到不行的小怪癖,现在开始让你觉得比起有趣,更多是烦人。你渐渐意识到,你可能是在和一个傻逼谈恋爱。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R6-angry.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="stick figure couple sitting on opposite ends of a couch, angry"></a></p><p>有时情况还会更糟——蝴蝶和彩虹变成了憋屈和幻灭,曾经把你托起来的那段关系,现在感觉像是把你困在一个盒子里。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R7-Cage.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="stick figure in a cage"></a></p><p>之前在爱情的迷雾里看不到的那些缺点,一下子全糊你脸上,像一块拖着你往下沉的重物。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R8-ball-and-chain.png" target="_blank" rel="noreferrer"><img src="'+h+'" alt="stick figure ball and chain"></a></p><p>很多恋情就在这里画上句号了。</p><p>但也许,在见识了伴侣的阴暗面之后,你后退一步,把好的坏的一起摆出来长时间地端详。你把玫瑰色眼镜和屎色眼镜都收起来,看看自己真正在跟谁谈恋爱:一个立体的、独一无二的、美好的、混蛋的人类。</p><p>一个最棒的人。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R9-best.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="stick figure couple laughing together"></a></p><p>也是最糟的人。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R10-worst.png" target="_blank" rel="noreferrer"><img src="'+d+'" alt="stick figure couple arguing with each other"></a></p><p>是你的队友。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R11-teammate.png" target="_blank" rel="noreferrer"><img src="'+_+'" alt="stick figures holding hands in a crowd"></a></p><p>是你的靠山。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R12-rock.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="stick figure consoling another stick figure"></a></p><p>然后你决定,你喜欢自己拥有的这一切。</p><p>于是你俩的人生继续一起往前走。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R13-beam-1.jpg" target="_blank" rel="noreferrer"><img src="'+b+'" alt="couple walking down blue road"></a></p><p>但就在事情变得简单的时候,另一件事开始发生了:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/08/R14-beam-2.jpg" target="_blank" rel="noreferrer"><img src="'+f+'" alt="edges of blue road start to crack; concerned stick figure"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/R15-beam-3.jpg" target="_blank" rel="noreferrer"><img src="'+y+'" alt="blue road gets narrower"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/R16-beam-4.jpg" target="_blank" rel="noreferrer"><img src="'+k+'" alt="stick figure couple huddled on a thin blue beam (their relationship) between &quot;soul-crushing breakup&quot; and &quot;permanent marriage till you die&quot;"></a></p><p>在世界大多数地方,社会不喜欢一段感情拖得太久。对社会来说,一段关系不过是一块试验田——一个为「那个决定」做准备的孵化器。如果谈了太多年却还没做出「那个决定」,社会就会认定肯定哪里出了问题。为了帮你把这个错拨乱反正,社会会从四面八方开始向这对情侣施压。</p><p>有些人比社会更大。我们大多数人不是。对我们大多数人来说,社会的规则就是我们的规则,当你和你的那个人走在你俩的蓝色平衡木上时,你能感觉到脚下能走的地方在你周围一点点消融。是时候做出「那个决定」了。</p><p>你的关系需要被转换成「永远拥有一切」或「再也一无所有」。快了。</p><p>普通人其实并没有做出「这个决定」的能力。我们进化出来是为了过短暂的一生,在那种一生里根本没有什么持续 60 年、改变人生的承诺这回事。我们进化于小型社区,没有这么多的可选项。而且大多数人在面对「这个决定」时,恋爱经验相对贫乏,对自己成年后的状态也理解得不完整——而这个成年的自己,很多时候还刚刚开始存在没多久。</p><p>但社会才不管这些。所以,你得决定。</p><p>人类想出了四种做「这个决定」的主要方法:</p><p><strong>方法 1)让对方决定</strong></p><p>处理「这个决定」最省事的方法就是——基本上不去处理它。你采取一种被动的态度,好像你坐在一只木筏上顺流而下,完全无法控制水流把你带去哪里——你被惯性和势能牵着走。一旦到了 25 岁上下,你就等着进入下一段感情,然后跟那个碰巧出现的人结婚,时机由对方来定(如果对方愿意的话),完全不管这段感情对你来说到底合不合适。</p><p><strong>方法 2)让你内心的原始力量厮杀决出胜负</strong></p><p>对于那些决心更主动地做「这个决定」的人,下一个最省力的方法就是让情绪和原始力量来替你搞定。做「这个决定」时你会意识到,「你」其实是一堆声音的集合,每个声音都来自进化史上的不同阶段。日常生活的稳态中,每个声音都有它的角色,但当遇到「这个决定」这种罕见又重大的时刻,你脑袋里突然就爆发出一场争夺影响力的大乱斗——而没有谁比你的原始力量打得更凶。几位主要选手:</p><p><strong>爱</strong></p><p>在内心深处,大多数人都是同情心强的角色。当你和一个人在一起够久,你通常最终会爱上这个人——哪怕你并不喜欢他们。你了解他们的整个故事,这让你在乎他们,而他们对你的依赖让你对他们产生巨大的忠诚感。这种爱和你对家人及最亲密的朋友的爱是同一种,即使「陷入爱河」的那种感觉早已褪去,它仍能满格地存在。而对许多人来说,这种深厚的情感连接让他们觉得和伴侣分手基本是不可思议的事。在一段健康、牢固的关系里,用这种方式做「这个决定」很美好;但在一段不健康的关系里,这就是一场悲剧。</p><p><strong>恐惧</strong></p><p>人类最擅长的就是基于恐惧做出重大人生决定,而说到「这个决定」,可怕的东西可太多了。</p><p>一个充满恐惧的人在看天平左边(「灵魂被碾碎的分手」那一边)时,可能会看到各种各样的东西:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/fear-breakup-2.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt="fear monsters on the &quot;soul-crushing breakup&quot; side"></a></p><p>天平右边也好不到哪里去。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/fear-marriage-2.png" target="_blank" rel="noreferrer"><img src="'+R+'" alt="fear monsters on the &quot;permanent marriage till you die&quot; side"></a></p><p>不同的人对这些恐惧的感受强度不同,而对于那些被恐惧主宰生活的人来说,事情通常挺简单的:哪种恐惧最狠地揪住他们的衣领,哪种就替他们做了「这个决定」。</p><p><strong>自我 (Ego)</strong></p><p>与此同时,你的自我正低头盯着一块写字板。取决于你的自我看重什么,这块板上可能列着一份清单,描述你理想中的伴侣——外貌、年龄、家庭背景、智力、工作、财富、大致的性格类型等等。或者这块板上写着一个故事,一个很久以前就写好的、关于你人生该怎么过的故事。你的自我会审视你当下的处境,看它和板上写的东西对得上对不上,然后根据结果来做「这个决定」。</p><p>在这一切分析进行的同时,你的自我有时也会发现自己非常饥饿——渴望被仰慕、被关注、渴望征服。如果这种饥饿感变得太强烈,它会把自我压得完全变形,以至于不管写字板上写的什么,自我最终都可能改投一票。</p><p><strong>性欲 (Sex Drive)</strong></p><p>你的性欲不是个复杂的角色。如果它每天午饭都吃烤奶酪三明治,然后某天你问它要不要试试自助餐,它一定会说好。当然,除非那份烤奶酪他妈的实在太顶了。</p><p>于是这四种原始力量,连同其他几种,同时开口表达意见。在有些人身上,所有声音对最终裁决意见一致。在另一些人身上,这些声音互相冲突,但其中一个声音大到把其他声音全都压过去了。这两种情况下,「这个决定」都挺容易做的。</p><p>但如果你的原始力量给不出一个明确答案,又该怎么办?</p><p><strong>方法 3)交给直觉</strong></p><p>不知为何,我们的肚子挺有智慧的,当「这个决定」不那么明显时,问问你的直觉有时候还真能奏效。</p><p>你的直觉靠的是你的第六感,它只问一个简单的问题:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/gut.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt="gut - &quot;does this feel right?&quot;"></a></p><p>而让直觉之所以是直觉的,是它回答这个问题时不会反复琢磨——它就是知道答案:一个简单的「是」或一个简单的「不是」。直觉不处理细枝末节的东西,这让它特别适合那种大而二元的问题,比如「这个决定」。</p><p>对很多人来说,这一招管用。</p><p>但有些人不会甘心做被动型决定者,也不会做情绪型决定者、直觉型决定者——面对这个特定的决定,他们不会去听任何原始的或本能的声音。他们会<em>不顾</em>那些声音,去把事情彻底搞清楚——依靠经验、证据、数据和事实。他们不会被本能驱动、不会被恐惧驱动、不会被自我驱动、也不会被性欲驱动——他们的向导是<em>理性</em>。</p><p>大脑型决定者。</p><p>而当他们必须做出「那个决定」的时候,他们就麻烦大了。</p><p><strong>方法 4)用大脑想清楚</strong></p><p>前额叶皮层可以说是大脑里的大脑。它是你身上负责筛选信息、制定计划和预测、权衡证据的那一部分。它非常擅长利用所学的东西得出结论——只要它知道游戏规则,并且能拿到正确的信息——来判断该怎么做、该采取什么行动。而到了「那个决定」的时刻,你的大脑会做它一贯遇到岔路口时会做的事——它会尝试思考、评估、分析,一路推理出最优的理性答案。</p><p>像「那个决定」这么重要、这么永久性的事情,是需要笃定感的,而笃定感需要一个来源。没有笃定感的来源,就没有「那个决定」。</p><p>心的笃定感来源,是它对另一个人的爱与在乎。自我 (ego) 的笃定感来源,是它对自己那张评分表的信仰。恐惧和性欲的笃定感来源,就是显而易见的——恐惧和性。直觉的笃定感来源,是从经验中冒出来的一种本能感觉。而一个惯性驱动的人,他们的笃定感是从别人的笃定感那里借来的。这些来源,就是让人们能相对轻松地做出「那个决定」的东西。</p><p>大脑能听见这些声音,但每一次它都会否定它们的笃定,因为在大脑看来,那种确信来自一个不理性的地方。对大脑而言,唯一值得尊敬的笃定感来源,是可靠的证据。</p><p>祝你好运。</p><p>如果你平时是个「大脑型」的人,那么到了「那个决定」时刻,你反而希望自己不是自己。因为大脑虽然优点很多,但在这种结果至关重要、而证据又极难获取的情境下,它的表现并不好。我们来看看这场面可能是怎样的:</p><p>也许你先转头看向平衡木的「结婚」那一侧——你看到一栋房子。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/house.jpg" target="_blank" rel="noreferrer"><img src="'+T+'" alt="house"></a></p><p>那就是你即将签约入住的那种生活的房子。你很享受你们的关系,所以你对房子里可能有什么感到兴奋。但这栋房子同时又神秘莫测,因为你其实并不真的知道你自己或者你的伴侣作为配偶会是什么样子,也不知道你们俩将来会怎么成长、怎么改变。这里没多少实打实的证据。</p><p>于是你转过身,看向平衡木的「分手」那一侧。你看到一条路,一对情侣正沿着那条路走下去。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/road.jpg" target="_blank" rel="noreferrer"><img src="'+P+'" alt="stick figure couple walking down a road"></a></p><p>那条路,就是如果你从当前这段关系里走出来、往前走,最终会过上的那种生活;而那段路上的婚姻,就是你最终会进入的那段婚姻。那段本来可能会有的婚姻。</p><p>那会是一段什么样的婚姻,那条路上又藏着怎样的冒险?也许那条路上的人生会比现在这栋房子里的一切都幸福得多,也许你现在的伴侣去了别处也会更幸福。又或者你回头一看,发现自己犯下了这辈子最大的错误。对那另一条路一无所知,你根本没法拿它来跟这边的房子做比较。再说一遍,没有真正的证据。</p><p>于是你转而仔细审视自己唯一有真实信息的东西:你现在这段感情。</p><p>你决定做一张大表,把你对这段关系喜欢的和不喜欢的一切都列出来——一张关系评估表。你最后画出来的东西长这样:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Venn.png" target="_blank" rel="noreferrer"><img src="'+t+'" alt="Venn: Things I Want to Have in a Relationship and Things I Don&#39;t Want to Deal With in a Relationship. (from left to right) blue: Things I Wish I Had, green: Things I&#39;m Happy I Have, yellow: Things I Wish I Didn&#39;t Have to Deal With, red: Things I&#39;m Happy I Don&#39;t Have to Deal With"></a></p><p>真他妈棒——然后呢?所有的关系——不管是好的还是烂的——画出来的图都是这样,四个区域(蓝、绿、黄、红)里都有内容。而以你那点儿可怜的恋爱经验和婚姻见识,你根本没法判断你这张图到底是像你希望的那样前景光明,还是里面藏着你没看出来的、日后会酿成大麻烦的危险信号。你试着把自己的关系跟朋友们的比一比——但你很难知道别人的关系里到底是什么样,而且每段关系都那么复杂、那么独特,基本上就是拿苹果比橘子。</p><p>没有办法在任何一个方向上构建出一个滴水不漏的论证,你对这件事就迟迟拿不出什么坚定的信念。因为赌注实在太大,你开始草木皆兵,生怕做错决定,每次你以为自己想通了,又立刻开始怀疑自己。</p><p>整件事很快变成一场脑内酷刑。你试图说服自己对婚姻感觉良好,提醒自己每段关系都有瑕疵、婚姻的本质就是接纳——但接着你意识到,一个人在勉强凑合、跟错的人在一起时,说出来的话也一模一样。在这两种情况下,图里的绿区和红区都足够提供充分的素材,让你拼出一整套「这是个绝佳决定」的论据。反过来,如果你想唱唱反调,琢磨琢磨这段婚姻可能<em>不</em>适合你的理由,图里的蓝区和黄区也能让你轻而易举地做到——不管分手到底是明智之举还是愚蠢之举。</p><p>而且,因为这张图和它的四个象限让你可以毫不费力地为自己的关系和这个决定编造出任何听起来很有说服力的说法,所以你会担心,任何感觉像是&quot;确信&quot;的东西,其实只是你落入了某个由恐惧、自尊或其他深层动机编织出来的叙事陷阱。</p><p>无法得出可信结论的大脑人,就变成了瘫痪型婚前关系人 (Paralyzed Pre-Marriage Relationship Person)。一个 PPMRP 有三个选择:</p><p><strong>1) 拖延。</strong> 拖到你死,拖到你的伴侣死,或者拖到你的伴侣跟你分手。</p><p><strong>2) 掉头回去,屈服于某个原始力量。</strong> 也许再等一段时间,你对 36 岁还单身的恐惧就会压过你对理性的坚持?</p><p><strong>3) 想出一个真正有用的决策试金石。</strong></p><p>假设你不觉得前两个选项理想,那我们就来聊聊试金石这件事。</p><p>选项 3 中&quot;真正有用&quot;这几个字很重要,因为人们经常想出的那些决策试金石,其实什么都告诉不了你。比如:</p><p><strong>过于宽泛、一刀切的试金石,是糟糕的试金石。</strong></p><p>比如,&quot;如果三年过去我还在为这段关系煎熬,那大概说明这段关系不适合我。&quot;或者,&quot;我们既然在一起这么久了,肯定是有原因的。&quot;再或者,&quot;如果我还想跟别人上床,那一定说明我的心不在这段关系上。&quot;</p><p>这类试金石暗示的是:<em>所有</em>为结婚决定煎熬的人都该分手,或者<em>每一对</em>在一起很久的情侣都该结婚,或者处在一段美好关系里的人<em>没有一个</em>还想跟别人上床。不同的人之所以会煎熬、会长久在一起、会觉得自己花心——或者其他 100 种情形——原因完全不同,所以这种笼统的陈述根本毫无用处。</p><p><strong>永远得出&quot;我们应该结婚&quot;这个答案的试金石,是糟糕的试金石。</strong></p><p>比如,&quot;当我想象他们和别人站在婚礼圣坛上,那画面太可怕了——这一定说明我该娶/嫁 TA。&quot;或者,&quot;上个月我们分手了三天,我想 TA 想得受不了——这已经告诉我一切了。&quot;再或者,&quot;我在乎 TA 胜过一切,真心希望 TA 过得好——这就是我知道我想和 TA 在一起的原因。&quot;</p><p>这些试金石告诉你的,不过是:A) 你有占有欲,B) 你有依恋,C) 你爱这个人。在<em>大多数</em>长期关系里——不管好坏——身在其中的人对上面这三件事都有感觉。这类测试真正告诉你的唯一信息就是:你确实处在一段恋爱关系中。</p><p><strong>永远得出&quot;我们应该分手&quot;这个答案的试金石,是糟糕的试金石。</strong></p><p>任何一个类似这样的问题:&quot;这个人在所有重要方面都跟我完美契合吗?&quot;或者&quot;这个人是最适合我的人吗?&quot;</p><p>不,那个人不是在每一个重要方面都跟你完美契合的人。这种事在人类历史上从没发生过。同样地,世界上至少有几亿人符合你的性取向,而其中只有一个是最适合你的人。你这辈子和那个人出现在同一平方英里范围内的概率小到可以忽略,而你正在和那个人约会的概率则是——你没在和那个人约会。这种试金石式的问题,要么要求你对伴侣或世界抱有一种妄想式的看法,要么几乎注定会得出「你该分手,继续去寻找那位真命天子」的结论。</p><p>在「这个决定」中挣扎的人渴望被指引,而虽然上面这些说法都带着某种更宏大智慧的外壳,听起来像是能把你从「PPMRP 泥潭」里救出来的救命稻草,但它们其实根本没告诉你该怎么做。</p><p><strong>给大脑折磨型人的一个好办法</strong></p><p>我不是这方面的专家,我自己也没结婚——但我读过不少相关的东西,也在近距离观摩过一堆案例研究,亲眼看着朋友经历「这个决定」,并在过程中跟他们聊。我觉得只要用点常识,我们大概可以搞清楚一个绝望的大脑型人在这种情况下能做什么——那就试试看吧。</p><p>在我看来,一个好的系统可能就这么简单,分两步:</p><p><strong>第一步:通过思想实验,搞清楚你的直觉倾向哪边。</strong></p><p>直觉是真实存在的东西。就我们这里要说的而言,你的直觉就是你心里那个小孩,它单纯地<em>就是</em>更<em>想要</em>某一种结果,而不是另一种。</p><p>大脑型人的问题在于,他们按定义<em>就不是</em>直觉型人。直觉从一个前额叶皮层无法理解的神秘地方汲取智慧,这让大脑型人对直觉的结论心存疑虑。</p><p>在这里心存疑虑是没问题的,因为你直觉的智慧受限于你的经验,而且直觉常常会被时间证明是错的——但直觉的意见依然是重要的信息。</p><p>直觉型人对于如何就重大决定跟自己的直觉沟通,已经有很好的练习。大脑型人没有——而常见的那个直觉式问题——「这感觉对吗?」——对我们不管用。所以我们需要用思想实验,把你脑袋里那片嘈杂中的直觉之声单独分离出来。这类练习最好由你自己为自己设计,因为只有你了解你。不过下面是一些点子:</p><p>有一类思想实验会在你脑海里创造一个模拟场景,它就像钓鱼用的假饵,我们的目标是让你的直觉在那一刻被这个模拟骗到,扑上来咬饵,从而暴露它真正想要的是什么。</p><p>类似这样:「想象你被镇上的媒婆包办婚姻,她递给你一个信封,里面写着你未来配偶的名字。你打开信封,发现里面写的是你现在伴侣的名字。」这个画面可能会让你的心猛地一跳,说:「呼,还好!」也可能相反,让你的心稍稍一沉,哪怕只是一瞬间。不管哪种反应,都是有用的信息。</p><p>另一种思想实验试图触及「这段关系感觉对不对?」这个问题本该揭示的那种笼统的「是」或「否」的感受,但用的是些非常直白扎心的意象。</p><p>比如:「想象两块紧挨着的墓碑——你的和你伴侣的。感觉对吗?」</p><p>一些最能说明问题的思想实验,会试图把常常震耳欲聋的恐惧之声从问题里剥离,看看这样一来有没有什么变化,通过这种方式来听清直觉在说什么。</p><p>比如,要测试你抗拒分手是不是只是害怕分手本身这件事,你可以问:「如果我面前有一个巨大的绿色按钮,一按下去我就彻底单身了——所有从彼此公寓里取回东西的事都已经处理妥当,我生活里所有人也都已经知道了,我情感上也完全恢复过来、向前看了——事实上,我今晚还有个约会——我会按下这个按钮吗?」</p><p>或者如果真正的恐惧是害怕单身很多年、再也找不到新恋情,那么这个按钮除了以上功能之外还可以加上「而且我正沉浸在一段新恋情里」。</p><p>对永远承诺的恐惧可以用这样的问题试探出来:「如果这个「决定」不是在分手和结婚之间,而只是在分手和承诺再谈五年之间,我会怎么选?」</p><p>如果这类思想练习让你觉得你内心深处的自己在「支持」这段关系,那是个好兆头。</p><p>但这还不够。</p><p><strong>第 2 步)搞清楚你的底线 (deal-breakers) 是什么。</strong></p><p>让我们把之前那张关系评估图表拿回来:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Venn.png" target="_blank" rel="noreferrer"><img src="'+t+'" alt="relationship Venn diagram between &quot;things I want to have in a relationship&quot; and &quot;things I don&#39;t want to deal with in a relationship&quot;"></a></p><p>正如我们之前确立的,这张图表对「决定」该怎么做提供不了什么洞见,因为几乎每一段关系——不管是好的坏的、健康的还是有害的、能走到最后的还是注定失败的——都有一张类似的图表,总是勾中一些对的、勾中一些错的,同时也漏掉一些两边的东西。然而,某些图表画的是幸福的伴侣,另一些则不是。那区别在哪儿?</p><p>底线。</p><p>尽管这些图表显示我们对一段关系有很多很多的诉求,但我们能否幸福其实只<em>取决于</em>其中一小部分。</p><p>我们的关系图就像一个幸福拼图,绿区和黄区里的条目就是拼图碎片。看这张图时,正确的问题不是「这对我来说完美吗?」或「如果我的图长这样,我就自动会幸福吗?」正确的问题是:「我怎么用这些碎片,拼出让我和伴侣都幸福的方式?」如果你是个好拼图玩家,再加上一些努力和妥协——也就是一点点成年人的成熟——你大概是能拼出来的。</p><p><em>除非</em>这张图缺了某个你的底线 (deal-breaker)。</p><p>底线就是那些东西:如果它们不在你的关系里,你就<em>绝对</em>不会幸福。这些是再多的努力、妥协或成熟都无法弥补的。是你的「必须要有」——和「绝对不能有」。</p><p>底线通常长这样:</p><p>我完全想不出怎么跟一个 是 / 不是 ____ 的人幸福地在一起。</p><p>我完全想不出怎么跟一个 做 / 不做 ____ 的人幸福地在一起。</p><p>我完全想不出怎么跟一个 重视 / 不重视 ____ 的人幸福地在一起。</p><p>我完全想不出怎么跟一个 这样对我 / 不这样对我 ____ 的人幸福地在一起。</p><p>我完全想不出怎么跟一个 相信 / 不相信 ____ 的人幸福地在一起。</p><p>或者:</p><p>出于原则,我只会 / 绝不会跟一个 ____ 的人在一起。</p><p>大多数真正的底线是宽泛的——比如「我也许能爱上一个消极的人,但我永远不可能跟这样的人幸福地在一起。」或者「我绝不会跟一个让我自尊变低的人在一起。」或者「我绝不可能跟一个没有求知欲的人幸福地在一起。」或者干脆一点的:「我绝不可能跟一个拒绝要孩子的人幸福地在一起。」</p><p>更具体的底线有时也说得通——比如你可能太爱狗了,以至于跟一个不想养狗的人在一起真的会阻碍你成为一个幸福的人——但这种情况应该很少。</p><p>所有这些的关键在于:底线的数量应该非常少。这些不是「想要」——这些是「需要」。你的「想要」也很重要,但记住,只有已经通过了直觉测试的人才有资格进入底线测试——你的很多「想要」在我们系统的第一步里就已经被照顾到了。</p><p>了解自己的底线雷区能帮你在遇到合适的对象时认出来,但对已经在一段关系里的人也大有用处,因为它能让你看清一段关系里最棘手的一个方面:妥协。让自己不幸福的一个绝佳办法,就是在那些你希望是真的、但事实并非如此的东西上死不妥协。但让自己不幸福的另一个绝佳办法,是在自己的底线雷区上<em>太过</em>愿意妥协。所以这一点才这么重要——底线雷区不仅能帮决策者和单身的人搞清楚一段关系里什么是不可接受的,还能提醒那些已经做完决定的人:他们关系里的大部分问题其实很可能都<em>不是</em>底线雷区,完全可以放轻松点。因为好多关系问题归根结底,都是一方或双方把非底线雷区当成了底线雷区——或者反过来。</p><p>差不多就是这样。这套 &quot;直觉自查 / 底线雷区&quot; 系统在告诉你:所谓 &quot;决定&quot; 这个大脑烧穿的事,其实挺简单的——一段关系如果顺利通过了第 1 步和第 2 步,那就结婚。如果没通过,那就别结。</p><p>至少这套系统是这么说的。</p><p>但谁知道呢。感情关系复杂得没边儿。而且,对一件完全谈不上非黑即白的事,非要做一个非黑即白的二元决定,这本身就有点疯狂。</p><p>而且当然啦,就算这套系统是对的,实际操作也并不容易,因为评估第 1 步和第 2 步都不容易。对一个通常都活在自己脑子里的人来说,从直觉那里获取一个你能信得过的信号可不是小事——而搞清楚自己的底线雷区到底是什么,则需要对自己的灵魂来一次深潜。</p><p>但至少,眼下这算个系统——一个你可以抓住不放的系统。而这正是我们中一些人所需要的。</p><h2 id="" tabindex="-1"><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/R17-beam-5-1.png" target="_blank" rel="noreferrer"><img src="'+j+'" alt="stick figure hands clinging on to the (now very thin) blue balance beam"></a> <a class="header-anchor" href="#" aria-label="Permalink to &quot;[![stick figure hands clinging on to the (now very thin) blue balance beam](/images/marriage-decision/R17-beam-5-1.png)](https://waitbutwhy.com/wp-content/uploads/2016/09/R17-beam-5-1.png)&quot;">​</a></h2><p><strong>如果你喜欢这篇:</strong></p><p>Wait But Why 的另一篇深潜,聊的也是 &quot;该跟谁结婚&quot; 这个大难题:<strong><a href="https://waitbutwhy.com/2014/02/pick-life-partner.html" target="_blank" rel="noreferrer">如何挑选人生伴侣 (How to Pick a Life Partner)</a></strong></p><p>来自单身男士世界的一些延伸议题:<strong><a href="https://waitbutwhy.com/2013/10/10-types-of-30-year-old-single-guys.html" target="_blank" rel="noreferrer">10 类 30 岁单身男 (10 Types of 30-Year-Old Single Guys)</a></strong></p><h2 id="一旦你终于做完了-那个决定-紧接着你就要面对下一个决定-如何给宝宝起名字-how-to-name-a-baby" tabindex="-1">一旦你终于做完了 &quot;那个决定&quot;,紧接着你就要面对下一个决定:<strong><a href="https://waitbutwhy.com/2013/12/how-to-name-baby.html" target="_blank" rel="noreferrer">如何给宝宝起名字 (How to Name a Baby)</a></strong> <a class="header-anchor" href="#一旦你终于做完了-那个决定-紧接着你就要面对下一个决定-如何给宝宝起名字-how-to-name-a-baby" aria-label="Permalink to &quot;一旦你终于做完了 &quot;那个决定&quot;,紧接着你就要面对下一个决定:**[如何给宝宝起名字 (How to Name a Baby)](https://waitbutwhy.com/2013/12/how-to-name-baby.html)**&quot;">​</a></h2><p>如果你喜欢 Wait But Why,来订阅我们的**<a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a>**吧,新文章一出我们就发给你。</p><p>想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2016/09/marriage-decision.html&amp;description=The%20Marriage%20Decision:%20Everything%20Forever%20or%20Nothing%20Ever%20Again" target="_blank" rel="noreferrer"><img src="'+I+'" alt=""></a></p>',161)])])}const x=r(D,[["render",A]]);export{V as __pageData,x as default};
